/**
 * scripts/fetch-last-positions.js
 *
 * One-time script: fetches last international lineup for each of the 48 teams
 * from API-Football and maps grid positions to x/y pitch coordinates.
 *
 * Requires .team_id_cache.json (generated by fetch-team-history.js).
 *
 * Budget:
 *   - 48 fixture calls (GET /fixtures?team={id}&season=2025)
 *   - 48 lineup calls  (GET /fixtures?id={fixture_id})
 *   - TOTAL: 96 requests (free tier = 100/day)
 *
 * Usage:
 *   API_FOOTBALL_KEY=xxx node scripts/fetch-last-positions.js
 *   # or add API_FOOTBALL_KEY=xxx to .env
 *
 *   # Test with only N teams:
 *   API_FOOTBALL_KEY=xxx node scripts/fetch-last-positions.js --limit 5
 */

import fs   from 'fs'
import path from 'path'

// ─── LOAD ENV ────────────────────────────────────────────────
try {
  const env = fs.readFileSync(path.resolve('.env'), 'utf8')
  for (const line of env.split('\n')) {
    const [k, ...v] = line.split('=')
    if (k?.trim() && v.length) process.env[k.trim()] = v.join('=').trim()
  }
} catch {}

const API_KEY    = process.env.API_FOOTBALL_KEY
const API_BASE   = 'https://v3.football.api-sports.io'
const CACHE_PATH = path.resolve('.team_id_cache.json')
const STD_PATH   = path.resolve('public/data/standings.json')
const OUT_PATH   = path.resolve('public/data/last-positions.json')
const SEASONS    = [2025, 2024]
const DELAY_MS   = 1300

const limitArg = process.argv.indexOf('--limit')
const LIMIT    = limitArg !== -1 ? parseInt(process.argv[limitArg + 1]) : Infinity

if (!API_KEY) {
  console.error(`
❌  API_FOOTBALL_KEY not set.

Add it to your .env file:
  API_FOOTBALL_KEY=your_key_here

Get a free key at https://dashboard.api-football.com/
  `)
  process.exit(1)
}

if (!fs.existsSync(CACHE_PATH)) {
  console.error(`
❌  .team_id_cache.json not found.

Run fetch-team-history.js first to generate the team ID cache:
  node scripts/fetch-team-history.js
  `)
  process.exit(1)
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)) }

async function apiGet(endpoint, params = {}) {
  const url = new URL(`${API_BASE}${endpoint}`)
  Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, String(v)))
  const r = await fetch(url.toString(), {
    headers: { 'x-apisports-key': API_KEY },
    signal: AbortSignal.timeout(15000),
  })
  const data = await r.json()
  const remaining = r.headers.get('x-ratelimit-requests-remaining')
  if (remaining !== null) process.stdout.write(` [q:${remaining}]`)
  if (data.errors && Object.keys(data.errors).length > 0) {
    throw new Error(JSON.stringify(data.errors))
  }
  return data.response ?? []
}

// ─── POSITION MAPPING ────────────────────────────────────────

function normalizePos(pos) {
  if (!pos) return 'M'
  switch (pos.toUpperCase()) {
    case 'G': case 'GK':                                          return 'G'
    case 'D': case 'CB': case 'LB': case 'RB':
    case 'LWB': case 'RWB': case 'SW':                           return 'D'
    case 'M': case 'CM': case 'CDM': case 'DM':
    case 'CAM': case 'AM': case 'LM': case 'RM': case 'WM':      return 'M'
    case 'F': case 'CF': case 'ST': case 'LW': case 'RW':
    case 'SS': case 'FW':                                         return 'F'
    default:                                                       return 'M'
  }
}

// Map grid "row:col" to x/y pitch coordinates.
// BSD coordinate system: x=depth (0=own goal, 100=opp goal), y=width (0=left, 100=right)
function gridBasedPositions(startXI) {
  const byRow = {}
  for (const item of startXI) {
    const grid = item.player?.grid
    if (!grid) continue
    const [rowStr, colStr] = grid.split(':')
    const row = parseInt(rowStr)
    const col = parseInt(colStr)
    if (!byRow[row]) byRow[row] = []
    byRow[row].push({ ...item.player, col })
  }

  const rows = Object.keys(byRow).map(Number).sort((a, b) => a - b)
  if (rows.length < 2) return null

  const totalLines = rows.length
  const out = []

  rows.forEach((row, ri) => {
    const players = byRow[row].slice().sort((a, b) => a.col - b.col)
    const count   = players.length
    // x: GK at 5, outfield rows spread from 20 to 78
    const x = ri === 0 ? 5 : 20 + ((ri - 1) / Math.max(1, totalLines - 2)) * 58

    players.forEach(p => {
      const y = (100 / (count + 1)) * p.col
      out.push({
        x, y,
        pos:       normalizePos(p.pos),
        name:      p.name || '?',
        n:         50,
        player_id: `af-${p.id}`,
      })
    })
  })

  return out.length >= 11 ? out : null
}

// Fallback: group by pos field, spread laterally within each group
function posBasedPositions(startXI) {
  const groups = { G: [], D: [], M: [], F: [] }
  for (const item of startXI) {
    const pos = normalizePos(item.player?.pos)
    groups[pos].push(item.player)
  }

  const xByGroup = { G: 5, D: 22, M: 50, F: 74 }
  const out = []

  for (const [pos, players] of Object.entries(groups)) {
    if (!players.length) continue
    const x = xByGroup[pos]
    players.forEach((p, i) => {
      const y = (100 / (players.length + 1)) * (i + 1)
      out.push({
        x, y,
        pos,
        name:      p?.name || '?',
        n:         50,
        player_id: `af-${p?.id ?? i}`,
      })
    })
  }

  return out.length >= 11 ? out : null
}

function lineupToPositions(startXI) {
  if (!startXI?.length) return null
  const hasGrid = startXI.some(item => item.player?.grid)
  return hasGrid ? gridBasedPositions(startXI) : posBasedPositions(startXI)
}

// ─── MAIN ─────────────────────────────────────────────────────
async function main() {
  const idCache  = JSON.parse(fs.readFileSync(CACHE_PATH, 'utf8'))
  const std      = JSON.parse(fs.readFileSync(STD_PATH, 'utf8'))

  const bsdTeams = []
  for (const rows of Object.values(std.groups)) {
    for (const row of rows) bsdTeams.push({ id: row.team_id, name: row.team_name })
  }

  const teams = bsdTeams.slice(0, LIMIT)
  const approxReq = teams.filter(t => idCache[t.id]).length * 2
  console.log(`\n📋 ${teams.length} equipos · ${Object.keys(idCache).length} IDs cacheados`)
  console.log(`⚠️  Requests estimados: ~${approxReq} (límite diario: 100/día)\n`)

  const result = {}
  let found = 0

  for (const team of teams) {
    const apiId = idCache[team.id]
    if (!apiId) {
      console.log(`  ✗ ${team.name}: no cached API-Football ID`)
      continue
    }

    // ── Step 1: find most recent finished fixture ──────────────
    let lastFixture = null
    for (const season of SEASONS) {
      process.stdout.write(`  ${team.name} (s${season})`)
      let fixtures = []
      try {
        fixtures = await apiGet('/fixtures', { team: apiId, season })
      } catch (e) {
        process.stdout.write(` ⚠ ${e.message}\n`)
        await sleep(DELAY_MS)
        continue
      }

      const finished = fixtures
        .filter(f => ['FT', 'AET', 'PEN'].includes(f.fixture?.status?.short))
        .sort((a, b) => b.fixture.timestamp - a.fixture.timestamp)

      process.stdout.write(` → ${finished.length} finished`)

      if (finished.length > 0) {
        lastFixture = finished[0]
        break
      }
      await sleep(DELAY_MS)
    }

    if (!lastFixture) {
      process.stdout.write(` → no finished fixtures found\n`)
      await sleep(DELAY_MS)
      continue
    }

    const fixtureId   = lastFixture.fixture.id
    const fixtureDate = lastFixture.fixture.date?.slice(0, 10) ?? '?'
    const isHome      = lastFixture.teams.home.id === apiId
    const opponent    = isHome ? lastFixture.teams.away.name : lastFixture.teams.home.name
    const score       = `${lastFixture.goals.home ?? '?'}-${lastFixture.goals.away ?? '?'}`
    process.stdout.write(` · ${fixtureDate} vs ${opponent} ${score}`)

    // ── Step 2: fetch lineup for that fixture ──────────────────
    await sleep(DELAY_MS)
    let lineupResponse
    try {
      lineupResponse = await apiGet('/fixtures', { id: fixtureId })
    } catch (e) {
      process.stdout.write(` ⚠ lineup fetch: ${e.message}\n`)
      await sleep(DELAY_MS)
      continue
    }

    const fixtureData = lineupResponse[0]
    const lineups     = fixtureData?.lineups ?? []
    const teamLineup  = lineups.find(l => l.team.id === apiId)

    if (!teamLineup?.startXI?.length) {
      process.stdout.write(` → no lineup\n`)
      await sleep(DELAY_MS)
      continue
    }

    const positions = lineupToPositions(teamLineup.startXI)
    if (!positions) {
      process.stdout.write(` → position parse failed\n`)
      await sleep(DELAY_MS)
      continue
    }

    result[team.id] = {
      team_name:       team.name,
      api_football_id: apiId,
      fixture_id:      fixtureId,
      fixture_date:    fixtureDate,
      opponent,
      formation:       teamLineup.formation ?? '?',
      positions,
    }
    found++
    process.stdout.write(` ✓ ${positions.length} jugadores (${teamLineup.formation})\n`)
    await sleep(DELAY_MS)
  }

  // ─── Save output ───────────────────────────────────────────
  const output = {
    updated_at:     new Date().toISOString(),
    note:           'Posiciones del último partido internacional por equipo (API-Football lineups → coordenadas x/y)',
    teams_with_data: found,
    teams:          result,
  }
  fs.writeFileSync(OUT_PATH, JSON.stringify(output, null, 2))

  console.log(`\n✅ ${found}/${teams.length} equipos → public/data/last-positions.json`)

  // ─── Summary ───────────────────────────────────────────────
  const byMonth = {}
  for (const t of Object.values(result)) {
    const m = t.fixture_date.slice(0, 7)
    byMonth[m] = (byMonth[m] ?? 0) + 1
  }

  if (Object.keys(byMonth).length) {
    console.log('\n📅 Datos por mes:')
    for (const [month, count] of Object.entries(byMonth).sort()) {
      console.log(`   ${month}: ${count} equipo(s)`)
    }
  }

  const noData = teams.filter(t => idCache[t.id] && !result[t.id])
  if (noData.length) {
    console.log(`\n⚠️  Sin datos: ${noData.map(t => t.name).join(', ')}`)
  }
}

main().catch(err => {
  console.error('\n❌ Fatal:', err.message)
  process.exit(1)
})
